// src/github/markdown.ts
var COMMENT_MARKER = "<!-- lockscan -->";
var SEVERITY_EMOJI = {
  critical: "\u{1F534}",
  high: "\u{1F7E0}",
  moderate: "\u{1F7E1}",
  low: "\u{1F535}"
};
var SEVERITY_LABEL = {
  critical: "Critical",
  high: "High",
  moderate: "Moderate",
  low: "Low"
};
function packageSignals(pkg) {
  const signals = [];
  for (const v2 of pkg.knownVulns?.slice(0, 2) ?? []) {
    signals.push(`${v2.id}${v2.severity ? ` [${v2.severity}]` : ""}`);
  }
  if ((pkg.knownVulns?.length ?? 0) > 2) {
    signals.push(`+${pkg.knownVulns.length - 2} more CVEs`);
  }
  for (const f2 of pkg.securityFindings?.delta.slice(0, 3) ?? []) {
    signals.push(`\`${f2.label}\``);
  }
  if ((pkg.securityFindings?.delta.length ?? 0) > 3) {
    signals.push(`+${pkg.securityFindings.delta.length - 3} more patterns`);
  }
  if ((pkg.binaryFindings?.delta.length ?? 0) > 0) {
    signals.push(`binary anomaly (${pkg.binaryFindings.delta.length})`);
  }
  if (pkg.securityFindings?.platformDivergence) signals.push("platform divergence");
  if (pkg.metadataDelta?.publisherChanged) signals.push("publisher changed");
  if (pkg.metadataDelta?.buildSystemChanged) signals.push("build system changed");
  if (pkg.installHooks?.some((h) => h.isNew)) {
    const n = pkg.installHooks.filter((h) => h.isNew).length;
    signals.push(`${n} new install hook(s)`);
  }
  if (pkg.registryCheck?.potentialConfusion) signals.push("**dependency confusion**");
  if (pkg.registryCheck?.registryChanged) signals.push("registry changed");
  if (pkg.repoCheck?.releaseDropped) signals.push("release tag dropped");
  if ((pkg.registryInfo?.versionAgeDays ?? Infinity) < 1) signals.push("\u26A1 fresh publish");
  if (pkg.metadataDelta?.newBinaryWheels) signals.push("new binary wheels");
  if (pkg.metadataDelta?.licenseChanged) signals.push("license changed");
  return signals;
}
function packageRow(pkg) {
  const sev = packageMaxSeverity(pkg);
  if (!sev) return null;
  const badge = `${SEVERITY_EMOJI[sev]} ${SEVERITY_LABEL[sev]}`;
  const version = pkg.changeType === "updated" ? `\`${pkg.oldVersion}\` \u2192 \`${pkg.newVersion}\`` : `\`${pkg.newVersion ?? pkg.oldVersion ?? "?"}\``;
  const tag = pkg.isDev ? " *(dev)*" : !pkg.isDirect ? " *(transitive)*" : "";
  return `| ${badge} | \`${pkg.name}\`${tag} | ${version} | ${packageSignals(pkg).join(", ")} |`;
}
function formatMarkdown(report) {
  const { summary: summary2 } = report;
  const findingPkgs = report.lockfiles.flatMap((lf) => lf.packages).filter((p2) => packageMaxSeverity(p2) !== null);
  const meta = `| | |
|---|---|
| **Base** | \`${report.baseRef}\` |
| **Head** | \`${report.headRef}\` |
| **Analyzed** | ${summary2.analyzed} package(s) |
| **Ecosystems** | ${summary2.ecosystems.join(", ") || "none"} |
`;
  if (findingPkgs.length === 0) {
    return `## \u{1F50D} lockscan Security Report

` + meta + "\n\u2705 **No security findings.** All dependency changes look clean.\n";
  }
  const bySev = { critical: 0, high: 0, moderate: 0, low: 0 };
  for (const pkg of findingPkgs) {
    const s3 = packageMaxSeverity(pkg);
    bySev[s3]++;
  }
  const summaryParts = Object.entries(bySev).filter(([, n]) => n > 0).map(([s3, n]) => `${SEVERITY_EMOJI[s3]} ${n} ${SEVERITY_LABEL[s3]}`);
  const rows = findingPkgs.map(packageRow).filter(Boolean).join("\n");
  return `## \u{1F50D} lockscan Security Report

` + meta + `
> ${summaryParts.join(" \xB7 ")}

### Findings

| Severity | Package | Version | Signals |
|---|---|---|---|
` + rows + "\n";
}

// src/github/comment.ts
async function findExistingCommentId(octokit, owner, repo, issueNumber) {
  const { data: comments } = await octokit.rest.issues.listComments({
    owner,
    repo,
    issue_number: issueNumber,
    per_page: 100
  });
  return comments.find((c) => c.body?.includes(COMMENT_MARKER))?.id ?? null;
}
function splitRepo(repo) {
  const [owner, name] = repo.split("/");
  if (!owner || !name) throw new Error(`Invalid repo format: "${repo}" (expected owner/name)`);
  return { owner, repo: name };
}
async function postOrUpdateComment(markdown, prNumber, repo, token) {
  const octokit = getOctokit(token);
  const { owner, repo: repoName } = splitRepo(repo);
  const issueNumber = Number(prNumber);
  const body = `${COMMENT_MARKER}

${markdown}`;
  const existingId = await findExistingCommentId(octokit, owner, repoName, issueNumber);
  if (existingId != null) {
    await octokit.rest.issues.updateComment({ owner, repo: repoName, comment_id: existingId, body });
  } else {
    await octokit.rest.issues.createComment({ owner, repo: repoName, issue_number: issueNumber, body });
  }
}
async function resolvedComment(prNumber, repo, token) {
  const octokit = getOctokit(token);
  const { owner, repo: repoName } = splitRepo(repo);
  const issueNumber = Number(prNumber);
  const existingId = await findExistingCommentId(octokit, owner, repoName, issueNumber);
  if (existingId == null) return;
  const body = `${COMMENT_MARKER}

## \u{1F50D} lockscan Security Report

\u2705 **All findings resolved.** No security findings in the latest dependency changes.
`;
  await octokit.rest.issues.updateComment({ owner, repo: repoName, comment_id: existingId, body });
}

